Steps:
Step Description:
Go to playground
Execute query evaluateDynamicContent


{
  evaluateDynamicContent(
    storeId:""B2B-store""
    cultureName:""en-US""
    placeName:""DynamicContent""
    toDate: ""2022-12-23T12:00:00Z""


  )
  {
    items
    {
      id
      contentType
      name
      priority
      description
      dynamicProperties
      {
        name
        valueType
        value

      }
    }
    totalCount
  }
}

